import { supabaseAdmin } from '@/lib/supabase/admin';
import HeroSection from '@/components/ui/HeroSection';
import ProductCard from '@/components/ui/ProductCard';

export default async function CatalogPage() {
  const { data: products, error } = await supabaseAdmin
    .from('products')
    .select('id, name, price, description, warranty_days, max_claim_limit, thumbnail_url')
    .eq('is_archived', false);

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="p-8 text-red-500 bg-red-50 rounded-2xl">Gagal memuat produk.</div>
      </div>
    );
  }

  return (
    <main className="min-h-[100dvh] flex flex-col">
      <HeroSection />

      <section className="relative w-full py-24 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="mb-16">
            <span className="inline-flex items-center rounded-full px-3 py-1 text-[10px] font-medium tracking-[0.2em] uppercase bg-[var(--color-surface-card)] text-[var(--color-text-secondary)] ring-1 ring-inset ring-[var(--color-border-soft)] mb-4 shadow-sm">
              Catalog
            </span>
            <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-[var(--color-text-primary)]">
              Premium Collection
            </h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-6 lg:gap-8">
            {products?.map((product: any) => (
              <ProductCard key={product.id} product={product} />
            ))}
          </div>
        </div>
      </section>
    </main>
  );
}
